1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const INSURANCE_VALUE_MULTIPLIER = 10;
24	const insuranceValueFor = (type: string): number => BASE_PREMIUMS[type] * INSURANCE_VALUE_MULTIPLIER;
25	const DEDUCTIBLE = 100;
26	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
27	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
28	const CAP_MULTIPLIER = 2;
29	
30	type Item = { type: string; cursed?: boolean; enchantment?: number };
31	type QuoteStep = { op: "quote"; items: Array<Item> };
32	type Damage = { itemType: string; amount: number };
33	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
34	type Step = QuoteStep | ClaimStep;
35	type Customer = { yearsWithMHPCO: number };
36	type Scenario = { customer: Customer; steps: Array<Step> };
37	type Policy = { items: Array<Item>; remainingCap: number };
38	
39	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
40	
41	const countByType = (items: Item[]): Record<string, number> => {
42	  const counts: Record<string, number> = {};
43	  for (const item of items) {
44	    counts[item.type] = (counts[item.type] ?? 0) + 1;
45	  }
46	  return counts;
47	};
48	
49	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
50	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
51	
52	const subtotalForType = (type: string, count: number): number =>
53	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
54	
55	const policyBaseFor = (items: Item[]): number =>
56	  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));
57	
58	const isHighlyEnchanted = (item: Item): boolean =>
59	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
60	
61	const surchargeRate = (item: Item): number =>
62	  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
63	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
64	
65	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
66	
67	const itemSurchargesFor = (items: Item[]): number => sum(items.map(itemSurcharge));
68	
69	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
70	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
71	
72	const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
73	  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
74	
75	const firstInsuranceSurchargeFor = (policyBase: number): number =>
76	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
77	
78	const isFollowUpQuote = (quoteIndex: number): boolean => quoteIndex > 0;
79	
80	const followUpDiscountFor = (policyBase: number, quoteIndex: number): number =>
81	  isFollowUpQuote(quoteIndex) ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
82	
83	const surchargesFor = (items: Item[], policyBase: number): number =>
84	  itemSurchargesFor(items) + firstInsuranceSurchargeFor(policyBase);
85	
86	const discountsFor = (policyBase: number, customer: Customer, quoteIndex: number): number =>
87	  loyaltyDiscountFor(policyBase, customer) + followUpDiscountFor(policyBase, quoteIndex);
88	
89	const quotePremium = ({ items }: QuoteStep, customer: Customer, quoteIndex: number): number => {
90	  const policyBase = policyBaseFor(items);
91	  return Math.ceil(policyBase + surchargesFor(items, policyBase) - discountsFor(policyBase, customer, quoteIndex) + PROCESSING_FEE);
92	};
93	
94	const insuranceSumFor = (items: Item[]): number =>
95	  sum(items.map((item) => insuranceValueFor(item.type)));
96	
97	const payoutRateFor = (item: Item): number =>
98	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD ? HIGH_ENCHANTMENT_PAYOUT_RATE : 1;
99	
100	const insuredItemOfType = (policy: Policy, itemType: string): Item =>
101	  policy.items.find((i) => i.type === itemType)!;
102	
103	const payoutForDamage = (damage: Damage, policy: Policy): number =>
104	  Math.floor(damage.amount * payoutRateFor(insuredItemOfType(policy, damage.itemType)) - DEDUCTIBLE);
105	
106	const processClaim = (step: ClaimStep, policies: Policy[]): { payout: number; remainingCap: number } => {
107	  const policy = policies[step.policy];
108	  const payout = sum(step.incident.damages.map((d) => payoutForDamage(d, policy)));
109	  policy.remainingCap -= payout;
110	  return { payout, remainingCap: policy.remainingCap };
111	};
112	
113	const capFor = (items: Item[]): number => insuranceSumFor(items) * CAP_MULTIPLIER;
114	
115	const newPolicy = (items: Item[]): Policy =>
116	  ({ items, remainingCap: capFor(items) });
117	
118	const processQuote = (step: QuoteStep, customer: Customer, policies: Policy[]): { premium: number } => {
119	  const premium = quotePremium(step, customer, policies.length);
120	  policies.push(newPolicy(step.items));
121	  return { premium };
122	};
123	
124	export const runScenario = (input: unknown): unknown => {
125	  const scenario = input as Scenario;
126	  const policies: Policy[] = [];
127	  const results = scenario.steps.map((step) =>
128	    step.op === "quote"
129	      ? processQuote(step, scenario.customer, policies)
130	      : processClaim(step, policies)
131	  );
132	  return { results };
133	};
